    44→const normalizeProfileLayout = (layout) => {
    45→    const incomingSections = Array.isArray(layout?.sections) ? layout.sections : [];
    46→    const normalizedSections = [];
    47→
    48→    incomingSections.forEach((section) => {
    49→        if(!PROFILE_SECTION_IDS.includes(section?.id)){
    50→            return;
    51→        }
    52→        if(normalizedSections.find((item) => item.id === section.id)){
    53→            return;
    54→        }
    55→
    56→        normalizedSections.push({
    57→            id: section.id,
    58→            visible: section.visible !== false,
    59→            size: PROFILE_SECTION_SIZES.includes(section?.size) ? section.size : 'md'
    60→        });
    61→    });
    62→
    63→    PROFILE_SECTION_IDS.forEach((sectionId) => {
    64→        if(normalizedSections.find((section) => section.id === sectionId)){
    65→            return;
    66→        }
    67→
    68→        const defaultSection = DEFAULT_PROFILE_LAYOUT.sections.find((section) => section.id === sectionId);
    69→        normalizedSections.push({...defaultSection});
    70→    });
